import { Hono } from 'hono';
import { Context } from 'hono/types';

const app = new Hono();

app.post('/team', async (c: Context) => {
  const requestBody = await c.req.json();
  const teamName = requestBody.name;

  if (!teamName) {
    return c.json({ error: 'Team name is required' }, 400);
  }

  // Simulate creating a new team
  const newTeam = {
    id: Math.random().toString(36).substr(2, 9),
    name: teamName,
    owner: c.req.user.id, // Assuming the user ID is available in the request context
    members: [c.req.user.id]
  };

  // Emit team.created event (simulated)
  console.log('team.created', newTeam);

  return c.json(newTeam, 201);
});

export default app;

